/**
 * rugby-rss.mjs - Shared rugby RSS/account utilities
 *
 * Normalizes Instagram account handles from rugby metadata cache, applies
 * manual overrides, and builds stable account records for dashboard and note
 * generation.
 */

import { existsSync, readFileSync, readdirSync } from 'fs';
import { resolve, dirname, join, basename } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));

export const VAULT_ROOT = resolve(__dirname, '..', '..');
export const RUGBY_CACHE_DIR = join(VAULT_ROOT, '.cache', 'rugby');
export const RUGBY_OVERRIDES_FILE = join(VAULT_ROOT, 'Rugby', 'rss', 'account-overrides.json');

const DEFAULT_RSS_BASE = 'http://localhost:1200';
const DEFAULT_RSS_ROUTE = 'picnob';

export function getRugbyRssConfig() {
  return {
    base: normalizeBaseUrl(process.env.RSSHUB_URL ?? DEFAULT_RSS_BASE),
    route: normalizeRouteName(process.env.RUGBY_RSS_ROUTE ?? DEFAULT_RSS_ROUTE),
  };
}

export function extractInstagramUsername(title = '') {
  const match = String(title).match(/\bVideo by\s+([A-Za-z0-9._]+)/i);
  return sanitizeInstagramUsername(match?.[1] ?? '');
}

export function sanitizeInstagramUsername(value = '') {
  return String(value)
    .trim()
    .replace(/^@+/, '')
    .replace(/[^\w.]+$/g, '')
    .toLowerCase();
}

export function buildRugbyFeedUrl(username, options = {}) {
  const cleanUsername = sanitizeInstagramUsername(username);
  if (!cleanUsername) return '';

  const config = {
    ...getRugbyRssConfig(),
    ...options,
  };

  return `${normalizeBaseUrl(config.base)}${buildFeedPath(cleanUsername, config.route)}`;
}

export function buildRugbyAccounts({ vaultRoot = VAULT_ROOT, minPosts = 0 } = {}) {
  const cacheDir = join(vaultRoot, '.cache', 'rugby');
  const overrides = loadRugbyAccountOverrides(vaultRoot);
  const rssConfig = getRugbyRssConfig();

  if (!existsSync(cacheDir)) {
    return { accounts: [], totalPosts: 0 };
  }

  const rawFiles = readdirSync(cacheDir)
    .filter((file) => file.endsWith('.json') && !file.includes('-classified') && !file.includes('-gdrive'))
    .sort();

  const buckets = new Map();
  let totalPosts = 0;

  for (const file of rawFiles) {
    const metaPath = join(cacheDir, file);
    const meta = readJson(metaPath);
    if (!meta) continue;

    const uploader = String(meta.uploader ?? '').trim();
    if (!uploader) continue;

    totalPosts += 1;

    const uploaderId = String(meta.uploader_id ?? '').trim();
    const bucketKey = uploaderId ? `id:${uploaderId}` : `name:${uploader}`;

    if (!buckets.has(bucketKey)) {
      buckets.set(bucketKey, {
        name: uploader,
        uploader_id: uploaderId,
        posts: 0,
        categories: new Set(),
        username_candidates: new Map(),
        sample_post_ids: [],
      });
    }

    const bucket = buckets.get(bucketKey);
    bucket.posts += 1;

    if (meta.post_id && bucket.sample_post_ids.length < 5) {
      bucket.sample_post_ids.push(meta.post_id);
    }

    const titleUsername = extractInstagramUsername(meta.title ?? '');
    if (titleUsername) {
      bucket.username_candidates.set(
        titleUsername,
        (bucket.username_candidates.get(titleUsername) ?? 0) + 1
      );
    }

    const classPath = join(cacheDir, `${basename(file, '.json')}-classified.json`);
    const classification = readJson(classPath);
    if (classification?.skill_category) {
      bucket.categories.add(classification.skill_category);
    }
  }

  const accounts = [...buckets.values()]
    .map((bucket) => finalizeAccount(bucket, overrides, rssConfig))
    .filter((account) => account.posts >= minPosts)
    .sort((left, right) => {
      if (right.posts !== left.posts) return right.posts - left.posts;
      return left.name.localeCompare(right.name);
    });

  return { accounts, totalPosts };
}

export function loadRugbyAccountOverrides(vaultRoot = VAULT_ROOT) {
  const overrideFile = join(vaultRoot, 'Rugby', 'rss', 'account-overrides.json');
  if (!existsSync(overrideFile)) {
    return { byUploader: {}, byUploaderId: {} };
  }

  const parsed = readJson(overrideFile);
  return {
    byUploader: parsed?.byUploader ?? {},
    byUploaderId: parsed?.byUploaderId ?? {},
  };
}

function finalizeAccount(bucket, overrides, rssConfig) {
  const override =
    overrides.byUploaderId?.[bucket.uploader_id] ??
    overrides.byUploader?.[bucket.name] ??
    null;

  const candidates = [...bucket.username_candidates.entries()]
    .sort((left, right) => {
      if (right[1] !== left[1]) return right[1] - left[1];
      return left[0].localeCompare(right[0]);
    })
    .map(([username, count]) => ({ username, count }));

  const resolvedUsername = sanitizeInstagramUsername(
    override?.username ?? candidates[0]?.username ?? ''
  );

  const usernameSource = override?.username
    ? 'override'
    : resolvedUsername
      ? 'title'
      : 'missing';

  const usernameConfidence = override?.username
    ? 'override'
    : candidates.length <= 1
      ? (resolvedUsername ? 'high' : 'missing')
      : (candidates[0]?.count === bucket.posts ? 'high' : 'mixed');

  return {
    name: bucket.name,
    uploader_id: bucket.uploader_id,
    posts: bucket.posts,
    categories: [...bucket.categories].sort(),
    username: resolvedUsername,
    username_source: usernameSource,
    username_confidence: usernameConfidence,
    username_candidates: candidates,
    sample_post_ids: bucket.sample_post_ids,
    instagram_url: resolvedUsername ? `https://www.instagram.com/${resolvedUsername}/` : '',
    rss_url: buildRugbyFeedUrl(resolvedUsername, rssConfig),
  };
}

function buildFeedPath(username, routeName) {
  switch (normalizeRouteName(routeName)) {
    case 'picnob.info':
      return `/picnob.info/user/${username}`;
    case 'instagram2':
      return `/instagram/2/user/${username}`;
    case 'instagram-private':
      return `/instagram/user/${username}`;
    case 'picnob':
    default:
      return `/picnob/user/${username}`;
  }
}

function normalizeBaseUrl(value) {
  return String(value || DEFAULT_RSS_BASE).replace(/\/+$/, '');
}

function normalizeRouteName(value) {
  const route = String(value || DEFAULT_RSS_ROUTE).trim().toLowerCase();
  if (route === 'instagram/2' || route === 'instagram-2') return 'instagram2';
  if (route === 'instagram' || route === 'private') return 'instagram-private';
  return route || DEFAULT_RSS_ROUTE;
}

function readJson(filePath) {
  if (!existsSync(filePath)) return null;
  try {
    return JSON.parse(readFileSync(filePath, 'utf8'));
  } catch {
    return null;
  }
}

