/**
 * rugby-accounts.mjs - Generate Rugby/Coaching Accounts.md
 *
 * Builds a normalized coaching-account reference note from rugby metadata,
 * applying RSS handle overrides from Rugby/rss/account-overrides.json.
 */

import { existsSync, readFileSync } from 'fs';
import { resolve, dirname, join } from 'path';
import { fileURLToPath } from 'url';
import { buildFrontmatter, buildTable, writeNote, today } from '../lib/markdown.mjs';
import { parseFrontmatter } from '../lib/frontmatter.mjs';
import {
  buildRugbyAccounts,
  getRugbyRssConfig,
  RUGBY_OVERRIDES_FILE,
} from '../lib/rugby-rss.mjs';

const __dirname = dirname(fileURLToPath(import.meta.url));
const VAULT_ROOT = resolve(__dirname, '..', '..');
const OUTPUT_FILE = join(VAULT_ROOT, 'Rugby', 'Coaching Accounts.md');

export async function pull(flags = {}) {
  const minPosts = parsePositiveInt(flags['min-posts'], 3);
  const dryRun = Boolean(flags['dry-run']);
  const { accounts, totalPosts } = buildRugbyAccounts({ vaultRoot: VAULT_ROOT, minPosts });
  const rssConfig = getRugbyRssConfig();
  const created = getExistingCreatedDate();

  const feedReadyCount = accounts.filter((account) => account.username).length;
  const reviewQueue = accounts.filter((account) => account.username_confidence !== 'high' && account.username_confidence !== 'override');

  const content = [
    buildFrontmatter({
      title: 'Rugby Coaching Accounts',
      type: 'reference',
      tags: ['rugby', 'coaching', 'accounts', 'instagram', 'rss'],
      created,
      updated: today(),
    }),
    '',
    '# Rugby Coaching Accounts to Follow',
    '',
    `> Auto-generated from metadata cache. Accounts with ${minPosts}+ posts in the coaching library.`,
    `> ${accounts.length} unique accounts found across ${totalPosts} posts. ${feedReadyCount} accounts currently have RSS-ready usernames.`,
    '',
    '## Top Coaching Accounts',
    '',
    buildTopAccountsTable(accounts),
    '',
    '## RSS Feed Notes',
    '',
    `- RSS base URL: \`${rssConfig.base}\``,
    `- RSS route: \`${rssConfig.route}\``,
    `- Manual overrides file: \`${relativeOverridePath()}\``,
    '',
    '### RSSHub Quick Setup',
    '',
    '```bash',
    '# Docker (self-hosted, stable default)',
    'docker run -d --name rsshub -p 1200:1200 diygod/rsshub',
    '',
    '# Example working route',
    `# ${rssConfig.base}/picnob/user/craigmcleodrugby`,
    '```',
    '',
    '## OPML Feed Bundle',
    '',
    'Import this into any RSS reader that accepts OPML:',
    '',
    '```xml',
    buildOpml(accounts),
    '```',
    '',
  ];

  if (reviewQueue.length > 0) {
    content.push('## Username Review Queue', '');
    content.push(
      buildTable(
        ['Account', 'Posts', 'Chosen Username', 'Confidence', 'Candidates'],
        reviewQueue.map((account) => [
          account.name,
          String(account.posts),
          account.username || 'missing',
          account.username_confidence,
          account.username_candidates.map((candidate) => `${candidate.username}:${candidate.count}`).join(', ') || 'none',
        ])
      ),
      ''
    );
  }

  content.push(`*Generated from .cache/rugby metadata on ${today()}.*`, '');

  const note = content.join('\n');

  if (dryRun) {
    console.log(note);
    return { accounts: accounts.length, feedReady: feedReadyCount, totalPosts };
  }

  writeNote(OUTPUT_FILE, note);
  console.log(`\nRugby coaching accounts note updated: ${OUTPUT_FILE}`);
  console.log(`  Accounts      : ${accounts.length}`);
  console.log(`  RSS-ready     : ${feedReadyCount}`);
  console.log(`  Review queue  : ${reviewQueue.length}`);
  console.log(`  Route         : ${rssConfig.route}`);
  console.log(`  Base          : ${rssConfig.base}\n`);

  return { accounts: accounts.length, feedReady: feedReadyCount, reviewQueue: reviewQueue.length, totalPosts };
}

function buildTopAccountsTable(accounts) {
  return buildTable(
    ['Account', 'Posts', 'Instagram', 'RSS', 'Content Focus'],
    accounts.map((account) => [
      account.name,
      String(account.posts),
      account.instagram_url ? `[@${account.username}](${account.instagram_url})` : 'Unknown',
      account.rss_url ? `[RSS](${account.rss_url})` : '',
      account.categories.join(', '),
    ])
  );
}

function buildOpml(accounts) {
  const lines = [
    '<?xml version="1.0" encoding="UTF-8"?>',
    '<opml version="2.0">',
    '  <head><title>Rugby Coaching Feeds</title></head>',
    '  <body>',
    '    <outline text="Rugby Coaching" title="Rugby Coaching">',
  ];

  for (const account of accounts.filter((entry) => entry.rss_url && entry.instagram_url)) {
    lines.push(
      `      <outline text="${escapeXml(account.name)}" xmlUrl="${escapeXml(account.rss_url)}" htmlUrl="${escapeXml(account.instagram_url)}" />`
    );
  }

  lines.push('    </outline>', '  </body>', '</opml>');
  return lines.join('\n');
}

function getExistingCreatedDate() {
  if (!existsSync(OUTPUT_FILE)) return today();

  try {
    const text = readFileSync(OUTPUT_FILE, 'utf8');
    const { data } = parseFrontmatter(text);
    return data.created || today();
  } catch {
    return today();
  }
}

function relativeOverridePath() {
  return RUGBY_OVERRIDES_FILE.replace(`${VAULT_ROOT}\\`, '').replace(/\\/g, '/');
}

function escapeXml(value = '') {
  return String(value)
    .replace(/&/g, '&amp;')
    .replace(/"/g, '&quot;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function parsePositiveInt(value, fallback) {
  const parsed = Number.parseInt(String(value ?? ''), 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const { config } = await import('dotenv');
  config({ path: join(VAULT_ROOT, '.env') });
  pull({}).catch((error) => {
    console.error(error);
    process.exit(1);
  });
}

