function loadAccounts() {
  if (!existsSync(CACHE_DIR)) return [];

  const files = readdirSync(CACHE_DIR)
    .filter(f => f.endsWith('.json') && !f.includes('-classified') && !f.includes('-gdrive'));

  const accounts = {};

  for (const file of files) {
    try {
      const meta = JSON.parse(readFileSync(join(CACHE_DIR, file), 'utf8'));
      const name = meta.uploader || meta.channel || '';
      if (!name) continue;

      const id = meta.uploader_id || meta.channel_id || '';
      const titleMatch = (meta.title || '').match(/Video by (\w+)/);
      const username = titleMatch ? titleMatch[1] : '';

      if (!accounts[name]) {
        accounts[name] = { name, id, username: '', posts: 0, categories: new Set() };
      }
      accounts[name].posts++;
      if (username && username !== 'rugby') accounts[name].username = username;

      // Pull category from classification if available
      const clsFile = file.replace('.json', '-classified.json');
      const clsPath = join(CACHE_DIR, clsFile);
      if (existsSync(clsPath)) {
        try {
          const cls = JSON.parse(readFileSync(clsPath, 'utf8'));
          if (cls.skill_category) accounts[name].categories.add(cls.skill_category);
        } catch { /* skip */ }
      }
    } catch { /* skip */ }
  }

  return Object.values(accounts)
    .map(a => ({ ...a, categories: [...a.categories] }))
    .sort((a, b) => b.posts - a.posts);
}

