async function handleRsshubStatus(res) {
  const rssConfig = getRugbyRssConfig();
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 5000);

  try {
    const response = await fetch(rssConfig.base, {
      signal: controller.signal,
      redirect: 'follow',
    });

    sendJson(res, {
      ok: response.ok,
      reachable: true,
      status: response.status,
      base: rssConfig.base,
      route: rssConfig.route,
    });
  } catch (error) {
    sendJson(res, {
      ok: false,
      reachable: false,
      status: null,
      base: rssConfig.base,
      route: rssConfig.route,
      error: error?.name === 'AbortError' ? 'timeout' : String(error?.message ?? error),
    });
  } finally {
    clearTimeout(timeout);
  }
}

