/**
 * rugby-note-patch.mjs - Helpers for rugby markdown note read/write operations
 *
 * Focused on safe, markdown-backed persistence for dashboard-driven features.
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'fs';
import { basename, dirname } from 'path';
import { parseFrontmatter } from './frontmatter.mjs';

export function readMarkdownNoteSync(filePath) {
  if (!existsSync(filePath)) return null;

  const text = readFileSync(filePath, 'utf8');
  const { data, content } = parseFrontmatter(text);
  return {
    path: filePath,
    filename: basename(filePath),
    data,
    content,
    text,
  };
}

export function writeMarkdownNoteSync(filePath, { fields = {}, blockFields = {}, content = '' }) {
  mkdirSync(dirname(filePath), { recursive: true });

  const frontmatter = buildFrontmatterWithBlocks(fields, blockFields);
  const body = String(content || '').trim();
  const text = body ? `${frontmatter}\n\n${body}\n` : `${frontmatter}\n`;

  writeFileSync(filePath, text, 'utf8');
  return text;
}

export function slugifyNoteName(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/['"]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .replace(/-{2,}/g, '-');
}

export function buildFrontmatterWithBlocks(fields = {}, blockFields = {}) {
  const lines = ['---'];

  for (const [key, value] of Object.entries(fields)) {
    if (value === null || value === undefined) continue;
    lines.push(serializeField(key, value));
  }

  for (const [key, value] of Object.entries(blockFields)) {
    if (value === null || value === undefined) continue;
    lines.push(`${key}: |`);
    const block = String(value).split('\n');
    if (block.length === 0) {
      lines.push('  ');
      continue;
    }
    for (const line of block) {
      lines.push(`  ${line}`);
    }
  }

  lines.push('---');
  return lines.join('\n');
}

function serializeField(key, value) {
  if (Array.isArray(value)) {
    const items = value.map((item) => serializeArrayItem(item));
    return `${key}: [${items.join(', ')}]`;
  }

  if (typeof value === 'boolean' || typeof value === 'number') {
    return `${key}: ${value}`;
  }

  return `${key}: "${escapeString(String(value))}"`;
}

function serializeArrayItem(value) {
  if (typeof value === 'boolean' || typeof value === 'number') {
    return String(value);
  }

  return `"${escapeString(String(value))}"`;
}

function escapeString(value) {
  return value.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
}

