  writeMarkdownNoteSync(filePath, {
    fields: {
      type: 'rugby_practice_template',
      title: normalized.title,
      age_group: normalized.age_group,
      duration_minutes: normalized.duration_minutes,
      theme: normalized.theme,
      difficulty: normalized.difficulty,
      equipment: normalized.equipment,
      objectives: normalized.objectives,
      block_count: normalized.template_blocks.length,
      created: createdDate,
      updated: createdDate,
      tags: ['rugby', 'practice-template'],
    },
    blockFields: {
      template_blocks_json: blockJson,
    },
    content: buildTemplateBody(normalized),
  });

  return parsePracticeTemplate(filePath);
}

function parsePracticeTemplate(filePath) {
  const note = readMarkdownNoteSync(filePath);
  if (!note || note.data.type !== 'rugby_practice_template') return null;

  return {
    id: basename(filePath, '.md'),
    slug: basename(filePath, '.md'),
    path: filePath,
    title: String(note.data.title || basename(filePath, '.md')),
    age_group: String(note.data.age_group || 'Youth'),
    duration_minutes: parsePositiveInt(note.data.duration_minutes, 60),
    theme: String(note.data.theme || 'General'),
    difficulty: String(note.data.difficulty || 'intermediate'),
    equipment: normalizeStringArray(note.data.equipment),
    objectives: normalizeStringArray(note.data.objectives),
    template_blocks: parseBlocks(note.data.template_blocks_json),
    created: String(note.data.created || ''),
    updated: String(note.data.updated || ''),
    content: note.content,
  };
}

function parsePracticeSession(filePath) {
  const note = readMarkdownNoteSync(filePath);
  if (!note || note.data.type !== 'rugby_practice_session') return null;

  return {
    id: basename(filePath, '.md'),
    slug: basename(filePath, '.md'),
    path: filePath,
    title: String(note.data.title || basename(filePath, '.md')),
    date: String(note.data.date || ''),
    team: String(note.data.team || ''),
    age_group: String(note.data.age_group || 'Youth'),
    duration_minutes: parsePositiveInt(note.data.duration_minutes, 60),
    status: String(note.data.status || 'draft'),
    source_template: String(note.data.source_template || ''),
    session_blocks: parseBlocks(note.data.session_blocks_json),
    created: String(note.data.created || ''),
    updated: String(note.data.updated || ''),
    content: note.content,
  };
}

function normalizeTemplatePayload(payload) {
  const title = String(payload.title || '').trim();
  if (!title) {
    throw new Error('Template title is required');
  }

  const duration = parsePositiveInt(payload.duration_minutes, 75);
  const blocks = normalizeBlocks(payload.template_blocks, duration);

  return {
    title,
    age_group: String(payload.age_group || 'Youth').trim() || 'Youth',
    duration_minutes: duration,
    theme: String(payload.theme || 'General Skills').trim() || 'General Skills',
    difficulty: normalizeDifficulty(payload.difficulty),
    equipment: normalizeStringArray(payload.equipment),
    objectives: normalizeStringArray(payload.objectives),
    template_blocks: blocks,
  };
}

function normalizeBlocks(blocks, durationMinutes) {
  if (!Array.isArray(blocks) || blocks.length === 0) {
    return buildStarterBlocks(durationMinutes);
  }

  return blocks.map((block, index) => ({
    label: String(block.label || `Block ${index + 1}`).trim(),
    minutes: parsePositiveInt(block.minutes, 10),
    drills: normalizeDrillLinks(block.drills),
    notes: String(block.notes || '').trim(),
  }));
}

function buildStarterBlocks(durationMinutes) {
  const labels = ['Warm-up', 'Skill Block', 'Unit Block', 'Game Block', 'Review'];
  const weights = [0.15, 0.25, 0.2, 0.25, 0.15];
  const rawMinutes = weights.map((weight) => roundToFive(durationMinutes * weight));
  const total = rawMinutes.reduce((sum, value) => sum + value, 0);
  rawMinutes[rawMinutes.length - 1] += durationMinutes - total;

  return labels.map((label, index) => ({
    label,
    minutes: Math.max(5, rawMinutes[index]),
    drills: [],
    notes: '',
  }));
}

function buildTemplateBody(template) {
  const lines = [
    `# ${template.title}`,
    '',
    '## Overview',
    '',
    `- Age Group: ${template.age_group}`,
    `- Duration: ${template.duration_minutes} minutes`,
    `- Theme: ${template.theme}`,
    `- Difficulty: ${template.difficulty}`,
    '',
  ];

  if (template.objectives.length > 0) {
    lines.push('## Objectives', '');
    for (const objective of template.objectives) {
      lines.push(`- ${objective}`);
    }
    lines.push('');
  }

  if (template.equipment.length > 0) {
    lines.push('## Equipment', '');
    for (const item of template.equipment) {
      lines.push(`- ${item}`);
    }
    lines.push('');
  }

  lines.push('## Practice Blocks', '');

  template.template_blocks.forEach((block, index) => {
    lines.push(`### ${index + 1}. ${block.label} (${block.minutes} min)`, '');

    if (block.drills.length > 0) {
      lines.push(`- Drills: ${block.drills.join(', ')}`);
    } else {
      lines.push('- Drills: none assigned yet');
    }

    if (block.notes) {
      lines.push(`- Notes: ${block.notes}`);
    }

    lines.push('');
  });

  return lines.join('\n').trim();
}

function parseBlocks(raw) {
  if (!raw) return [];

  try {
    const parsed = JSON.parse(String(raw));
    if (!Array.isArray(parsed)) return [];
    return parsed.map((block, index) => ({
      label: String(block.label || `Block ${index + 1}`),
      minutes: parsePositiveInt(block.minutes, 10),
      drills: normalizeDrillLinks(block.drills),
      notes: String(block.notes || ''),
    }));
  } catch {
    return [];
  }
}

function normalizeDrillLinks(value) {
  if (!Array.isArray(value)) return [];

  return value
    .map((item) => String(item || '').trim())
    .filter(Boolean)
    .map((item) => (item.startsWith('[[') && item.endsWith(']]') ? item : `[[${item.replace(/^\[\[|\]\]$/g, '')}]]`));
}

function normalizeStringArray(value) {
  if (!Array.isArray(value)) return [];

  return value
    .map((item) => String(item || '').trim())
    .filter(Boolean);
}

function normalizeDifficulty(value) {
  const difficulty = String(value || 'intermediate').trim().toLowerCase();
  return ['beginner', 'intermediate', 'advanced'].includes(difficulty)
    ? difficulty
    : 'intermediate';
}

function parsePositiveInt(value, fallback) {
  const parsed = Number.parseInt(String(value ?? ''), 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

function readdirMarkdownNotes(dir) {
  if (!existsSync(dir)) return [];

  return readdirSync(dir)
    .filter((entry) => entry.endsWith('.md'))
    .map((entry) => join(dir, entry));
}

function roundToFive(value) {
  return Math.max(5, Math.round(value / 5) * 5);
}

