        '<p>Set the session shape now. Block editing, drill assignment, and session duplication follow in the next phase.</p>' +
        '<form class="planner-form" id="templateForm">' +
          '<label>Title<input type="text" id="templateTitle" placeholder="Youth Defence Pressure" required /></label>' +
          '<label>Age Group<select id="templateAge"><option>Flag</option><option>Mini</option><option selected>Youth</option><option>Junior</option><option>Senior</option></select></label>' +
          '<label>Duration (minutes)<input type="number" id="templateDuration" min="20" max="180" step="5" value="75" /></label>' +
          '<label>Theme<input type="text" id="templateTheme" placeholder="Defence" value="General Skills" /></label>' +
          '<label>Difficulty<select id="templateDifficulty"><option>beginner</option><option selected>intermediate</option><option>advanced</option></select></label>' +
          '<label>Equipment<textarea id="templateEquipment" placeholder="balls, cones, tackle bags"></textarea></label>' +
          '<label>Objectives<textarea id="templateObjectives" placeholder="One objective per line"></textarea></label>' +
          '<button type="submit" class="opml-btn">Save Template</button>' +
          '<div class="planner-status" id="plannerStatus"></div>' +
        '</form>' +
      '</section>' +
      '<section class="planner-panel">' +
        '<h2>Saved Templates</h2>' +
        '<p>' + allTemplates.length + ' template' + (allTemplates.length === 1 ? '' : 's') + ' currently available.</p>' +
        renderTemplateCollection() +
        '<h2 style="margin-top:18px;">Recent Sessions</h2>' +
        sessionSummary +
      '</section>' +
    '</div>';

  const form = document.getElementById('templateForm');
  if (form) {
    form.addEventListener('submit', submitTemplateForm);
  }
}

function renderTemplateCollection() {
  if (allTemplates.length === 0) {
    return '<div class="empty-state" style="padding:28px 12px;"><h2>No templates yet</h2><p>Save a starter template from the panel on the left.</p></div>';
  }

  return '<div class="planner-grid">' + allTemplates.map(renderTemplateCard).join('') + '</div>';
}

function renderTemplateCard(template) {
  const totalMinutes = (template.template_blocks || []).reduce((sum, block) => sum + (Number(block.minutes) || 0), 0);
  const blocks = (template.template_blocks || []).slice(0, 5).map((block) =>
    '<li><strong>' + escHtml(block.label || 'Block') + '</strong> · ' + escHtml(String(block.minutes || 0)) + ' min</li>'
  ).join('');

  return '<article class="planner-card">' +
    '<h3>' + escHtml(template.title || template.slug || 'Untitled Template') + '</h3>' +
    '<div class="planner-meta">' +
      '<span class="badge badge-age">' + escHtml(template.age_group || 'Youth') + '</span>' +
      '<span class="badge badge-diff-' + escHtml(template.difficulty || 'intermediate') + '">' + escHtml(template.difficulty || 'intermediate') + '</span>' +
      '<span class="badge" style="background:#f0f4e8;color:#2d5016;">' + escHtml(String(totalMinutes || template.duration_minutes || 0)) + ' min</span>' +
    '</div>' +
    '<div><strong>Theme:</strong> ' + escHtml(template.theme || 'General Skills') + '</div>' +
    '<div class="planner-note">Blocks: ' + escHtml(String(template.block_count || (template.template_blocks || []).length || 0)) + '</div>' +
    '<ol class="planner-blocks">' + blocks + '</ol>' +
  '</article>';
}

function renderSessionCard(session) {
  return '<article class="planner-card">' +
    '<h3>' + escHtml(session.title || session.slug || 'Untitled Session') + '</h3>' +
    '<div class="planner-meta">' +
      '<span class="badge badge-age">' + escHtml(session.age_group || 'Youth') + '</span>' +
      '<span class="badge" style="background:#e8f0e8;color:#2d5016;">' + escHtml(session.status || 'draft') + '</span>' +
    '</div>' +
    '<div><strong>Date:</strong> ' + escHtml(session.date || 'unscheduled') + '</div>' +
    '<div class="planner-note">Source template: ' + escHtml(session.source_template || 'none') + '</div>' +
  '</article>';
}

