async function submitTemplateForm(event) {
  event.preventDefault();

  const statusEl = document.getElementById('plannerStatus');
  if (statusEl) {
    statusEl.className = 'planner-status';
    statusEl.textContent = 'Saving...';
  }

  const payload = {
    title: document.getElementById('templateTitle').value.trim(),
    age_group: document.getElementById('templateAge').value,
    duration_minutes: Number(document.getElementById('templateDuration').value || 75),
    theme: document.getElementById('templateTheme').value.trim(),
    difficulty: document.getElementById('templateDifficulty').value,
    equipment: parseCommaList(document.getElementById('templateEquipment').value),
    objectives: parseLineList(document.getElementById('templateObjectives').value),
  };

  try {
    const response = await fetch('/api/templates', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });
    const result = await response.json();

    if (!response.ok) {
      throw new Error(result.error || 'Failed to save template');
    }

    await loadData();
    event.target.reset();
    document.getElementById('templateAge').value = 'Youth';
    document.getElementById('templateDuration').value = '75';
    document.getElementById('templateTheme').value = 'General Skills';
    document.getElementById('templateDifficulty').value = 'intermediate';

    if (statusEl) {
      statusEl.className = 'planner-status ok';
      statusEl.textContent = 'Template saved to Rugby/Practice Templates.';
    }
  } catch (error) {
    if (statusEl) {
      statusEl.className = 'planner-status err';
      statusEl.textContent = error.message || 'Failed to save template.';
    }
  }
}

function parseCommaList(value) {
  return String(value || '')
    .split(',')
    .map(item => item.trim())
    .filter(Boolean);
}

function parseLineList(value) {
  return String(value || '')
    .split(/\\r?\\n/)
    .map(item => item.trim())
    .filter(Boolean);
}

