export function createPracticeSession(payload = {}, { vaultRoot = VAULT_ROOT, overwrite = false } = {}) {
  const { sessionsDir } = ensurePracticeFolders(vaultRoot);
  const normalized = normalizeSessionPayload(payload);
  const slug = slugifyNoteName(payload.slug || `${normalized.date}-${normalized.title}`);

  if (!slug) {
    throw new Error('Session title is required');
  }

  const filePath = join(sessionsDir, `${slug}.md`);
  if (existsSync(filePath) && !overwrite) {
    throw new Error(`Session already exists: ${slug}`);
  }

  const existing = readMarkdownNoteSync(filePath);
  const createdDate = String(existing?.data.created || today());
  const blockJson = JSON.stringify(normalized.session_blocks, null, 2);

  writeMarkdownNoteSync(filePath, {
    fields: {
      type: 'rugby_practice_session',
      title: normalized.title,
      date: normalized.date,
      team: normalized.team,
      age_group: normalized.age_group,
      duration_minutes: normalized.duration_minutes,
      theme: normalized.theme,
      difficulty: normalized.difficulty,
      equipment: normalized.equipment,
      objectives: normalized.objectives,
      source_template: normalized.source_template,
      status: normalized.status,
      weather_notes: normalized.weather_notes,
      attendance_notes: normalized.attendance_notes,
      block_count: normalized.session_blocks.length,
      created: createdDate,
      updated: today(),
      tags: ['rugby', 'practice-session'],
    },
    blockFields: {
      session_blocks_json: blockJson,
    },
    content: buildSessionBody(normalized),
  });

  return parsePracticeSession(filePath);
}

