function buildSessionBody(session) {
  const lines = [
    `# ${session.title}`,
    '',
    '## Session Info',
    '',
    `- Date: ${session.date}`,
    `- Team: ${session.team || 'TBD'}`,
    `- Age Group: ${session.age_group}`,
    `- Duration: ${session.duration_minutes} minutes`,
    `- Theme: ${session.theme}`,
    `- Difficulty: ${session.difficulty}`,
    `- Status: ${session.status}`,
  ];

  if (session.source_template) {
    lines.push(`- Source Template: ${session.source_template}`);
  }

  lines.push('');

  if (session.objectives.length > 0) {
    lines.push('## Objectives', '');
    for (const objective of session.objectives) {
      lines.push(`- ${objective}`);
    }
    lines.push('');
  }

  if (session.equipment.length > 0) {
    lines.push('## Equipment', '');
    for (const item of session.equipment) {
      lines.push(`- ${item}`);
    }
    lines.push('');
  }

  if (session.weather_notes) {
    lines.push('## Weather Notes', '', session.weather_notes, '');
  }

  if (session.attendance_notes) {
    lines.push('## Attendance Notes', '', session.attendance_notes, '');
  }

  lines.push('## Session Blocks', '');

  session.session_blocks.forEach((block, index) => {
    lines.push(`### ${index + 1}. ${block.label} (${block.minutes} min)`, '');

    if (block.drills.length > 0) {
      lines.push(`- Drills: ${block.drills.join(', ')}`);
    } else {
      lines.push('- Drills: none assigned yet');
    }

    if (block.notes) {
      lines.push(`- Notes: ${block.notes}`);
    }

    lines.push('');
  });

  return lines.join('\n').trim();
}

