}

function normalizeTemplateReference(value) {
  const raw = String(value || '').trim();
  if (!raw) return '';
  if (raw.startsWith('[[') && raw.endsWith(']]')) return raw;
  return `[[${raw.replace(/^\[\[|\]\]$/g, '')}]]`;
}

