// ── Coaches tab ──────────────────────────────────────────────────────────
function renderDraftBlockCard(block, index) {
  const isActive = index === plannerActiveBlockIndex;
  const drillsHtml = block.drills.length > 0
    ? block.drills.map((drillRef, drillIndex) => renderDraftDrillItem(index, drillIndex, drillRef)).join('')
    : '<div class="planner-note">No drills assigned yet. Use Add to Practice from the drills tab.</div>';

  return '<article class="draft-block' + (isActive ? ' active' : '') + '" id="draft-block-' + index + '">' +
    '<div class="draft-block-header">' +
      '<button class="planner-mini-button' + (isActive ? ' active' : '') + '" onclick="setActivePlannerBlock(' + index + ')">' + (isActive ? 'Active Block' : 'Set Active') + '</button>' +
      '<input class="draft-block-title" type="text" value="' + escHtml(block.label || '') + '" onchange="updatePlannerBlockField(' + index + ', \\'label\\', this.value)" />' +
      '<div class="draft-block-controls">' +
        '<input type="number" min="5" max="90" step="5" value="' + escHtml(String(block.minutes || 0)) + '" onchange="updatePlannerBlockField(' + index + ', \\'minutes\\', this.value)" />' +
        '<button class="planner-mini-button" onclick="movePlannerBlock(' + index + ', -1)">Up</button>' +
        '<button class="planner-mini-button" onclick="movePlannerBlock(' + index + ', 1)">Down</button>' +
        '<button class="planner-mini-button" onclick="removePlannerBlock(' + index + ')">Remove</button>' +
      '</div>' +
    '</div>' +
    '<textarea class="draft-block-notes" placeholder="Coaching notes, setup, constraints" onchange="updatePlannerBlockField(' + index + ', \\'notes\\', this.value)">' + escHtml(block.notes || '') + '</textarea>' +
    '<div class="draft-drill-list">' + drillsHtml + '</div>' +
  '</article>';
}

function renderDraftDrillItem(blockIndex, drillIndex, drillRef) {
  const drill = getDrillByRef(drillRef);
  const fallbackId = getDrillIdFromRef(drillRef);
  const title = drill ? (drill.sub_skill || drill.canonical_term || drill.id) : fallbackId;
  const meta = drill
    ? [drill.skill_category, drill.difficulty].filter(Boolean).join(' - ')
    : 'Drill note reference';

  return '<div class="draft-drill-item">' +
    '<div>' +
      '<div class="draft-drill-title">' + escHtml(title || fallbackId || 'Drill') + '</div>' +
      '<div class="draft-drill-meta">' + escHtml(meta || '') + '</div>' +
    '</div>' +
    '<div class="draft-drill-actions">' +
      '<button class="planner-mini-button" onclick="movePlannerDrill(' + blockIndex + ', ' + drillIndex + ', -1)">Up</button>' +
      '<button class="planner-mini-button" onclick="movePlannerDrill(' + blockIndex + ', ' + drillIndex + ', 1)">Down</button>' +
      '<button class="planner-mini-button" onclick="removePlannerDrill(' + blockIndex + ', ' + drillIndex + ')">Remove</button>' +
    '</div>' +
  '</div>';
}

function renderAgeGroupOptions(selectedValue) {
  const options = ['Flag', 'Mini', 'Youth', 'Junior', 'Senior'];
  return options.map((option) =>
    '<option value="' + option + '"' + (option === selectedValue ? ' selected' : '') + '>' + option + '</option>'
  ).join('');
}

function renderDifficultyOptions(selectedValue) {
  const options = ['beginner', 'intermediate', 'advanced'];
  return options.map((option) =>
    '<option value="' + option + '"' + (option === selectedValue ? ' selected' : '') + '>' + option + '</option>'
  ).join('');
}

function newPlannerDraft() {
  plannerDraft = createBlankPlannerDraft();
  plannerActiveBlockIndex = 0;
  setPlannerMessage('Started a new draft. Use the drills tab to add content into the active block.', 'info');
  refreshPlannerUi();
}

function createBlankPlannerDraft() {
  return {
    title: '',
    age_group: selectedAge !== 'All' ? selectedAge : 'Youth',
    duration_minutes: 75,
    theme: 'General Skills',
    difficulty: 'intermediate',
    equipment_text: '',
    objectives_text: '',
    team: '',
    session_date: getTodayIso(),
    template_slug: '',
    source_template: '',
    blocks: buildPlannerStarterBlocks(75),
  };
}

function buildPlannerStarterBlocks(durationMinutes) {
  const labels = ['Warm-up', 'Skill Block', 'Unit Block', 'Game Block', 'Review'];
  const weights = [0.15, 0.25, 0.2, 0.25, 0.15];
  const rawMinutes = weights.map((weight) => roundPlannerBlock(durationMinutes * weight));
  const totalMinutes = rawMinutes.reduce((sum, value) => sum + value, 0);
  rawMinutes[rawMinutes.length - 1] += durationMinutes - totalMinutes;

  return labels.map((label, index) => ({
    label,
    minutes: Math.max(5, rawMinutes[index]),
    drills: [],
    notes: '',
  }));
}

function roundPlannerBlock(value) {
  return Math.max(5, Math.round(value / 5) * 5);
}

function normalizePlannerDraft(rawDraft) {
  const source = rawDraft && typeof rawDraft === 'object' ? rawDraft : createBlankPlannerDraft();
  const durationMinutes = parsePlannerInt(source.duration_minutes, 75);

  return {
    title: String(source.title || '').trim(),
    age_group: normalizePlannerAgeGroup(source.age_group),
    duration_minutes: durationMinutes,
    theme: String(source.theme || 'General Skills').trim() || 'General Skills',
    difficulty: normalizePlannerDifficulty(source.difficulty),
    equipment_text: normalizePlannerText(source.equipment_text, source.equipment),
    objectives_text: normalizePlannerText(source.objectives_text, source.objectives),
    team: String(source.team || '').trim(),
    session_date: normalizePlannerDate(source.session_date || source.date),
    template_slug: String(source.template_slug || source.slug || '').trim(),
    source_template: normalizePlannerTemplateReference(source.source_template),
    blocks: normalizePlannerBlocks(source.blocks || source.template_blocks || source.session_blocks, durationMinutes),
  };
}

function normalizePlannerBlocks(blocks, durationMinutes) {
  if (!Array.isArray(blocks) || blocks.length === 0) {
    return buildPlannerStarterBlocks(durationMinutes);
  }

  return blocks.map((block, index) => ({
    label: String((block && block.label) || ('Block ' + (index + 1))).trim() || ('Block ' + (index + 1)),
    minutes: parsePlannerInt(block && block.minutes, 10),
    drills: Array.isArray(block && block.drills) ? block.drills.map(normalizePlannerDrillReference).filter(Boolean) : [],
    notes: String((block && block.notes) || ''),
  }));
}

function normalizePlannerDrillReference(value) {
  const raw = String(value || '').trim();
  if (!raw) return '';
  if (raw.startsWith('[[') && raw.endsWith(']]')) return raw;
  return '[[' + getDrillIdFromRef(raw) + ']]';
}

function normalizePlannerAgeGroup(value) {
  const valid = ['Flag', 'Mini', 'Youth', 'Junior', 'Senior'];
  const raw = String(value || '').trim();
  return valid.includes(raw) ? raw : 'Youth';
}

function normalizePlannerDifficulty(value) {
  const valid = ['beginner', 'intermediate', 'advanced'];
  const raw = String(value || 'intermediate').trim().toLowerCase();
  return valid.includes(raw) ? raw : 'intermediate';
}

function normalizePlannerText(rawValue, arrayValue) {
  if (typeof rawValue === 'string') return rawValue;
  if (!Array.isArray(arrayValue)) return '';
  return arrayValue.join('\n');
}

function normalizePlannerDate(value) {
  const raw = String(value || '').trim();
  if (raw.length === 10 && raw.charAt(4) === '-' && raw.charAt(7) === '-') {
    return raw;
  }
  return getTodayIso();
}

function normalizePlannerTemplateReference(value) {
  const raw = String(value || '').trim();
  if (!raw) return '';
  if (raw.startsWith('[[') && raw.endsWith(']]')) return raw;
  return '[[' + raw + ']]';
}

function parsePlannerInt(value, fallbackValue) {
  const parsed = Number.parseInt(String(value ?? ''), 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallbackValue;
}

function clampPlannerActiveBlock() {
  if (!plannerDraft || !Array.isArray(plannerDraft.blocks) || plannerDraft.blocks.length === 0) {
    plannerActiveBlockIndex = 0;
    return;
  }

  if (plannerActiveBlockIndex < 0) plannerActiveBlockIndex = 0;
  if (plannerActiveBlockIndex >= plannerDraft.blocks.length) {
    plannerActiveBlockIndex = plannerDraft.blocks.length - 1;
  }
}

function sumBlockMinutes(blocks) {
  if (!Array.isArray(blocks)) return 0;
  return blocks.reduce((sum, block) => sum + (Number(block && block.minutes) || 0), 0);
}

function getActiveBlockLabel() {
  plannerDraft = normalizePlannerDraft(plannerDraft);
  clampPlannerActiveBlock();
  const block = plannerDraft.blocks[plannerActiveBlockIndex];
  return block ? (block.label || 'Active Block') : 'Active Block';
}

function getTodayIso() {
  return new Date().toISOString().slice(0, 10);
}

function getDrillIdFromRef(value) {
  const raw = String(value || '').trim();
  if (raw.startsWith('[[') && raw.endsWith(']]')) {
    return raw.slice(2, -2).trim();
  }
  return raw;
}

function getDrillByRef(drillRef) {
  const drillId = getDrillIdFromRef(drillRef);
  return allDrills.find((drill) => drill.id === drillId);
}

function refreshPlannerUi() {
  persistPlannerDraft();
  renderPlanner();
  renderDrills();
}

function persistPlannerDraft() {
  try {
    localStorage.setItem(plannerDraftStorageKey, JSON.stringify(plannerDraft));
    localStorage.setItem(plannerBlockStorageKey, String(plannerActiveBlockIndex));
  } catch {
    // Ignore localStorage issues
  }
}

function restorePlannerDraft() {
  try {
    const rawDraft = localStorage.getItem(plannerDraftStorageKey);
    const rawIndex = localStorage.getItem(plannerBlockStorageKey);
    plannerDraft = rawDraft ? normalizePlannerDraft(JSON.parse(rawDraft)) : createBlankPlannerDraft();
    plannerActiveBlockIndex = Number.parseInt(String(rawIndex || '0'), 10) || 0;
  } catch {
    plannerDraft = createBlankPlannerDraft();
    plannerActiveBlockIndex = 0;
  }

  clampPlannerActiveBlock();
}

function setPlannerMessage(message, kind) {
  plannerMessage = String(message || '');
  plannerMessageKind = kind || 'info';
}

function updateDraftField(field, value) {
  plannerDraft = normalizePlannerDraft(plannerDraft);

  if (field === 'duration_minutes') {
    plannerDraft.duration_minutes = parsePlannerInt(value, plannerDraft.duration_minutes || 75);
  } else if (field === 'source_template') {
    plannerDraft.source_template = normalizePlannerTemplateReference(value);
  } else if (field === 'equipment_text' || field === 'objectives_text') {
    plannerDraft[field] = String(value || '');
  } else {
    plannerDraft[field] = String(value || '').trim();
  }

  setPlannerMessage('Draft updated.', 'info');
  refreshPlannerUi();
}

function setActivePlannerBlock(index) {
  plannerDraft = normalizePlannerDraft(plannerDraft);
  plannerActiveBlockIndex = index;
  clampPlannerActiveBlock();
  setPlannerMessage('Active block set to ' + getActiveBlockLabel() + '.', 'info');
  refreshPlannerUi();
}

function updatePlannerBlockField(index, field, value) {
  plannerDraft = normalizePlannerDraft(plannerDraft);
  const block = plannerDraft.blocks[index];
  if (!block) return;

  if (field === 'minutes') {
    block.minutes = parsePlannerInt(value, block.minutes || 10);
  } else {
    block[field] = String(value || '');
  }

  setPlannerMessage('Block updated.', 'info');
  refreshPlannerUi();
}

function addPlannerBlock() {
  plannerDraft = normalizePlannerDraft(plannerDraft);
  plannerDraft.blocks.push({
    label: 'Block ' + (plannerDraft.blocks.length + 1),
    minutes: 10,
    drills: [],
    notes: '',
  });
  plannerActiveBlockIndex = plannerDraft.blocks.length - 1;
  setPlannerMessage('Added a new block and made it active.', 'info');
  refreshPlannerUi();
  focusPlannerBlock();
}

function removePlannerBlock(index) {
  plannerDraft = normalizePlannerDraft(plannerDraft);
  if (plannerDraft.blocks.length === 1) {
    setPlannerMessage('At least one block is required.', 'err');
    renderPlanner();
    return;
  }

  plannerDraft.blocks.splice(index, 1);
  clampPlannerActiveBlock();
  setPlannerMessage('Block removed.', 'info');
  refreshPlannerUi();
}

function movePlannerBlock(index, direction) {
  plannerDraft = normalizePlannerDraft(plannerDraft);
  const targetIndex = index + direction;
  if (targetIndex < 0 || targetIndex >= plannerDraft.blocks.length) return;

  const blocks = plannerDraft.blocks;
  const current = blocks[index];
  blocks[index] = blocks[targetIndex];
  blocks[targetIndex] = current;

  if (plannerActiveBlockIndex === index) {
    plannerActiveBlockIndex = targetIndex;
  } else if (plannerActiveBlockIndex === targetIndex) {
    plannerActiveBlockIndex = index;
  }

  setPlannerMessage('Block order updated.', 'info');
  refreshPlannerUi();
}

function movePlannerDrill(blockIndex, drillIndex, direction) {
  plannerDraft = normalizePlannerDraft(plannerDraft);
  const block = plannerDraft.blocks[blockIndex];
  if (!block) return;

  const targetIndex = drillIndex + direction;
  if (targetIndex < 0 || targetIndex >= block.drills.length) return;

  const drillRef = block.drills[drillIndex];
  block.drills[drillIndex] = block.drills[targetIndex];
  block.drills[targetIndex] = drillRef;

  setPlannerMessage('Drill order updated.', 'info');
  refreshPlannerUi();
}

function removePlannerDrill(blockIndex, drillIndex) {
  plannerDraft = normalizePlannerDraft(plannerDraft);
  const block = plannerDraft.blocks[blockIndex];
  if (!block) return;

  block.drills.splice(drillIndex, 1);
  setPlannerMessage('Removed drill from ' + (block.label || 'block') + '.', 'info');
  refreshPlannerUi();
}

function addDrillToDraft(drillId) {
  plannerDraft = normalizePlannerDraft(plannerDraft);
  clampPlannerActiveBlock();

  const block = plannerDraft.blocks[plannerActiveBlockIndex];
  if (!block) return;

  const drillRef = normalizePlannerDrillReference(drillId);
  if (block.drills.includes(drillRef)) {
    setPlannerMessage('That drill is already in ' + getActiveBlockLabel() + '.', 'info');
    renderPlanner();
    renderDrills();
    return;
  }

  block.drills.push(drillRef);
  const drill = allDrills.find((item) => item.id === drillId);
  const drillLabel = drill ? (drill.sub_skill || drill.canonical_term || drill.id) : drillId;
  setPlannerMessage('Added ' + drillLabel + ' to ' + getActiveBlockLabel() + '.', 'ok');
  refreshPlannerUi();
}

function loadTemplateIntoDraft(templateSlug) {
  const template = allTemplates.find((item) => item.slug === templateSlug);
  if (!template) {
    setPlannerMessage('Template not found.', 'err');
    renderPlanner();
    return;
  }

  plannerDraft = normalizePlannerDraft({
    title: template.title,
    age_group: template.age_group,
    duration_minutes: template.duration_minutes,
    theme: template.theme,
    difficulty: template.difficulty,
    equipment_text: (template.equipment || []).join('\n'),
    objectives_text: (template.objectives || []).join('\n'),
    team: plannerDraft && plannerDraft.team ? plannerDraft.team : '',
    session_date: plannerDraft && plannerDraft.session_date ? plannerDraft.session_date : getTodayIso(),
    template_slug: template.slug,
    source_template: '[[' + (template.title || template.slug) + ']]',
    blocks: clonePlannerValue(template.template_blocks || []),
  });
  plannerActiveBlockIndex = 0;
  setPlannerMessage('Loaded template into the draft.', 'ok');
  refreshPlannerUi();
  focusPlannerBlock();
}

function focusPlannerBlock() {
  setTimeout(() => {
    const element = document.getElementById('draft-block-' + plannerActiveBlockIndex);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, 40);
}

function clonePlannerValue(value) {
  return JSON.parse(JSON.stringify(value));
}

function buildPlannerTemplatePayload() {
  plannerDraft = normalizePlannerDraft(plannerDraft);
  return {
    slug: plannerDraft.template_slug || undefined,
    overwrite: Boolean(plannerDraft.template_slug),
    title: plannerDraft.title,
    age_group: plannerDraft.age_group,
    duration_minutes: plannerDraft.duration_minutes,
    theme: plannerDraft.theme,
    difficulty: plannerDraft.difficulty,
    equipment: parseListText(plannerDraft.equipment_text),
    objectives: parseListText(plannerDraft.objectives_text),
    template_blocks: clonePlannerValue(plannerDraft.blocks),
  };
}

function buildPlannerSessionPayload() {
  plannerDraft = normalizePlannerDraft(plannerDraft);
  return {
    title: plannerDraft.title,
    date: plannerDraft.session_date,
    team: plannerDraft.team,
    age_group: plannerDraft.age_group,
    duration_minutes: plannerDraft.duration_minutes,
    theme: plannerDraft.theme,
    difficulty: plannerDraft.difficulty,
    equipment: parseListText(plannerDraft.equipment_text),
    objectives: parseListText(plannerDraft.objectives_text),
    source_template: plannerDraft.source_template,
    status: 'draft',
    session_blocks: clonePlannerValue(plannerDraft.blocks),
  };
}

function parseListText(value) {
  const items = [];
  const lines = String(value || '').split('\n');

  for (const line of lines) {
    const parts = line.split(',');
    for (const part of parts) {
      const cleaned = part.split('\r').join('').trim();
      if (cleaned) items.push(cleaned);
    }
  }

  return items;
}

async function saveDraftAsTemplate() {
  plannerDraft = normalizePlannerDraft(plannerDraft);
  if (!plannerDraft.title) {
    setPlannerMessage('Title is required before saving a template.', 'err');
    renderPlanner();
    return;
  }

  setPlannerMessage('Saving template...', 'info');
  renderPlanner();

  try {
    const response = await fetch('/api/templates', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(buildPlannerTemplatePayload()),
    });
    const result = await response.json();

    if (!response.ok) {
      throw new Error(result.error || 'Failed to save template');
    }

    const currentDate = plannerDraft.session_date;
    const currentTeam = plannerDraft.team;
    plannerDraft = normalizePlannerDraft({
      ...plannerDraft,
      title: result.template.title,
      age_group: result.template.age_group,
      duration_minutes: result.template.duration_minutes,
      theme: result.template.theme,
      difficulty: result.template.difficulty,
      equipment_text: (result.template.equipment || []).join('\n'),
      objectives_text: (result.template.objectives || []).join('\n'),
      template_slug: result.template.slug,
      source_template: '[[' + (result.template.title || result.template.slug) + ']]',
      blocks: clonePlannerValue(result.template.template_blocks || []),
      session_date: currentDate,
      team: currentTeam,
    });
    setPlannerMessage('Template saved to Rugby/Practice Templates.', 'ok');
    persistPlannerDraft();
    await loadData();
  } catch (error) {
    setPlannerMessage(error.message || 'Failed to save template.', 'err');
    renderPlanner();
  }
}

async function saveDraftAsSession() {
  plannerDraft = normalizePlannerDraft(plannerDraft);
  if (!plannerDraft.title) {
    setPlannerMessage('Title is required before saving a session.', 'err');
    renderPlanner();
    return;
  }

  setPlannerMessage('Saving session...', 'info');
  renderPlanner();

  try {
    const response = await fetch('/api/sessions', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(buildPlannerSessionPayload()),
    });
    const result = await response.json();

    if (!response.ok) {
      throw new Error(result.error || 'Failed to save session');
    }

    setPlannerMessage('Session saved to Rugby/Practice Sessions.', 'ok');
    persistPlannerDraft();
    await loadData();
  } catch (error) {
    setPlannerMessage(error.message || 'Failed to save session.', 'err');
    renderPlanner();
  }
}

function printPlannerDraft() {
  showTab('planner');
  setTimeout(() => window.print(), 40);
}

