    const response = await fetch('/api/templates', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });
    const result = await response.json();

    if (!response.ok) {
      throw new Error(result.error || 'Failed to save template');
    }

    await loadData();
    const refreshedStatusEl = document.getElementById('plannerStatus');
    if (refreshedStatusEl) {
      refreshedStatusEl.className = 'planner-status ok';
      refreshedStatusEl.textContent = 'Template saved to Rugby/Practice Templates.';
    }
  } catch (error) {
    if (statusEl) {
      statusEl.className = 'planner-status err';
      statusEl.textContent = error.message || 'Failed to save template.';
    }
  }
}

